11	let XiaopengBLEConnectionHeartbeat = "[BLE心跳]"
12	extension XiaopengBLEConnection {
13	    func startHeartbeat() {
14	        let timer = Timer(timeInterval: 5, repeats: true) { [weak self] _ in
15	            self?.checkIfNeedSendHeartbeat()
16	        }
17	        RunLoop.current.add(timer, forMode: .common)
18	        self.heartBeatTimer = timer
19	    }
20	    
21	    func stopHeartbeat() {
22	        Log.i(XiaopengBLEConnectionHeartbeat, "BLE心跳定时器关闭")
23	        if self.heartBeatTimer != nil {
24	            self.heartBeatTimer?.invalidate()
25	            self.heartBeatTimer = nil
26	        }
27	    }
28	    
29	    private func checkIfNeedSendHeartbeat() {
30	        if self.bleSwitcheCheck.isNeedsHeartbeat {
31	            // 发送心跳
32	            sendHeartbeat()
33	        }
34	    }
35	    
36	    private func sendHeartbeat() {
37	        guard connectState == .Available else {
38	            return
39	        }
40	        
41	        // 发送心跳 polling 1.0 同时使用从蓝牙发送，这里暂时全部使用主蓝牙发
42	        // 组装
43	        Log.i(XiaopengBLEConnectionHeartbeat, "BLE心跳开始发送")
44	       
45	        if presenter?.vehiclePreference.function.IS_POLLINGFIRST == true,
46	           let vehicle = presenter as? XiaopengVehicle,
47	           let rssiManager = vehicle.rssiManager {
48	            rssiManager.sendHeartBeat { success in
49	                if success {
50	                    Log.i(XiaopengBLEConnectionHeartbeat, "BLE心跳发送成功 - 从蓝牙")
51	                } else {
52	                    Log.i(XiaopengBLEConnectionHeartbeat, "BLE心跳发送失败 - 从蓝牙，改为主蓝牙发送")
53	                    self.sendMainBleHeartbeat()
54	                }
55	            }
56	        } else {
57	            sendMainBleHeartbeat()
58	        }
59	    }
60	    
61	    func sendMainBleHeartbeat() {
62	        guard let bleSendDataBuilder = bleSendDataBuilder as? BleSendDataBuilder else { return }
63	        
64	        bleHeartbeatCancellable = bleSendDataBuilder.buildHeartbeat()
65	            .flatMap({[weak self] data in
66	                guard let self else {
67	                    return Fail<AnyObject?, VehicleError>(error: VehicleError(code: .EnvironmentError, desc: "未知错误", channel: .BLE)).eraseToAnyPublisher()
68	                }
69	                return self.sendBleData(data)
70	            })
71	            .sink(receiveCompletion: { completion in
72	                switch completion {
73	                case .finished:
74	                    Log.i(XiaopengBLEConnectionHeartbeat, "BLE心跳发送完成")
75	                case .failure(let error):
76	                    Log.i(XiaopengBLEConnectionHeartbeat, "BLE心跳构包失败", error.description)
77	                }
78	            }, receiveValue: { data in
79	                Log.i("BLE心跳发送成功")
80	            })
81	    }
82	    
83	}
