5	//  App运行状态，用于记录前后台状态、是否在车控页，以及Polling、摇一摇是否开启，是否进入泊车、是否连上手表等信息
6	//   SDK 会根据这些App运行状态决定是否发送MQTT和蓝牙心跳、是否重连MQTT和蓝牙等
7	//
8	//  Created by yangcy on 2024/02/05.
9	//
10	
11	import Foundation
12	import Combine
13	
14	@objc(XPAppRunState)
15	open class AppRunState: NSObject {
16	    static let kTag = "App运行状态"
17	    @objc public static let shared = AppRunState()
18	       
19	    private var cancellables = Set<AnyCancellable>()
20	    private var applicationState: UIApplication.State // 缓存系统状态，用于比较是否变化
21	    
22	    @Published @objc private(set) public var isInBackground: Bool = false // App 是否在后台
23	    @Published @objc private(set) public var isInVehicleControlPage: Bool = false // 是否在车控页
24	    @Published @objc private(set) public var isWatchReachable: Bool = false // 是否已连上手表
25	    @Published @objc private(set) public var isShakeActive: Bool = false // 摇一摇是否激活
26	    @Published @objc private(set) public var isWillTerminate: Bool = false // 是否将要terminate
27	    
28	    // TODO: 多车时下方待调整
29	    @Published @objc private(set) public var isOnParking: Bool = false // 是否正在泊车
30	    @Published @objc private(set) public var isDigitalKeyDeleting: Bool = false // 是否正在删除钥匙
31	    
32	    var appSwitchCount: Int = 0 // App前后台切换次数统计
33	    var backgroundTime: TimeInterval = 0 // 进入后台时间戳
34	    // TODO: 注意，这里的App运行状态都是些App车控业务重大状态参数，不能随意添加业务参数
35	
36	    override init() {
37	        applicationState = ApplicationState.shared.applicationState
38	        isWillTerminate = ApplicationState.shared.isWillTerminate
39	        super.init()
40	        
41	        isInBackground = applicationState == .background
42	
43	        Log.i(tag: Self.kTag, "初始值 applicationState:", applicationState.rawValue, "前后台标记 isInBackground:", isInBackground)
44	        
45	        appStateObserver()
46	    }
47	    
48	    deinit {
49	    }
50	    
51	    func appStateObserver() {
52	        ApplicationState.shared.$applicationState.sink {[weak self] state in
53	            Log.i(tag: Self.kTag, "监听到AppState变化，applicationState:", state.rawValue)
54	            guard let self else { return }
55	
56	            if (self.applicationState != state) {
57	                self.applicationState = state
58	                let isBackground = self.applicationState == .background
59	                if (self.isInBackground != isBackground) {
60	                    self.isInBackground = isBackground
61	                    self.appSwitchCount += 1
62	                    if self.isInBackground {
63	                        self.backgroundTime = CACurrentMediaTime()
64	                    }
65	                    Log.i(tag: Self.kTag, "前后台标记发生变化 isInBackground:", self.isInBackground)
66	                }
67	            }
68	        }.store(in: &cancellables)
69	        
70	        ApplicationState.shared.$isWillTerminate.sink {[weak self] state in
71	            Log.i(tag: Self.kTag, "监听到App生命周期变化，applicationState:", state)
72	            guard let self else { return }
73	            if (self.isWillTerminate != state) {
74	                self.isWillTerminate = state
75	                Log.i(tag: Self.kTag, "App生命周期变化 isWillTerminate:", isWillTerminate)
76	            }
77	        }.store(in: &cancellables)
78	    }
79	    
80	    @objc public func setInVehicleControlPage(_ flag: Bool) {
81	        Log.i(tag: Self.kTag, "setInVehicleControlPage:", flag)
82	        if (self.isInVehicleControlPage != flag) {
83	            self.isInVehicleControlPage = flag
84	        }
85	    }
86	    
87	    @objc public func setOnParking(_ flag: Bool) {
88	        Log.i(tag: Self.kTag, "setOnParking:", flag)
89	        if (self.isOnParking != flag) {
90	            self.isOnParking = flag
91	        }
92	    }
93	    
94	    @objc public func setDigitalKeyDeleting(_ flag: Bool) {
95	        Log.i(tag: Self.kTag, "setDigitalKeyDeleting:", flag)
96	        if (self.isDigitalKeyDeleting != flag) {
97	            self.isDigitalKeyDeleting = flag
98	        }
99	    }
100	
101	    @objc public func setWatchReachable(_ flag: Bool) {
102	        Log.i(tag: Self.kTag, "setWatchReachable:", flag)
103	        if (self.isWatchReachable != flag) {
104	            self.isWatchReachable = flag
105	        }
106	    }
107	    
108	    @objc public func setShakeActive(_ flag: Bool) {
109	        Log.i(tag: Self.kTag, "setShakeActive:", flag)
110	        if (self.isShakeActive != flag) {
111	            self.isShakeActive = flag
112	        }
113	    }
114	
115	}
