205	    func controlBleHandlerLife(address: String?, cccVid: String?, isResuce: Bool = false) {
206	        guard let presenter = self.presenter else {
207	            Log.i(tag: "bleLife", "presenter为nil,return")
208	            return
209	        }
210	        let cccVid = cccVid ?? presenter.vehiclePreference.extInfo?.cccVid
211	        let category = BLEHandlerFactory.bleCreateCategory(presenter: presenter)
212	        
213	        guard category != .NONE else {
214	            Log.i(tag: "bleLife", "category is none, remove old")
215	            self.removeOriginBleHandler()
216	            self.bleCategory = .NONE
217	            self.tboxRunException = false
218	            return
219	        }
220	        Log.i(tag: "bleLife", "category is \(category)")
221	        if self.bleCategory != category {
222	            self.removeOriginBleHandler()
223	            self.cleanBleInfoCache()
224	            self.getVaildKeySettingData()
225	        }
226	        if self.tboxRunException != isResuce {
227	            self.removeOriginBleHandler()
228	            self.tboxRunException = isResuce
229	        }
230	        
231	        guard let oldHandler = self.bleHandler else {
232	            Log.i(tag: "bleLife", "old ble handler is nil")
233	            guard let bleHandler = BLEHandlerFactory.createBleKeyHandler(macAddress: address, cccVid: cccVid, bleCategory: category, delegate: self, presenter: presenter, isResuce: isResuce) else {
234	                Log.i(tag: "bleLife", "create ble handler failed, return")
235	                return
236	            }
237	            return self.createNewBleHandler(bleHandler: bleHandler, bleCategory: category, presenter: presenter)
238	        }
239	        Log.i(tag: "bleLife", "old ble handler is not nil")
240	        if category != .PHONE_UWB_KEY {
241	            guard let macAddress = address else {
242	                Log.i(tag: "bleLife", "address is nil,remove origin")
243	                self.removeOriginBleHandler()
244	                return
245	            }
246	            if oldHandler.macAddress == macAddress {
247	                Log.i(tag: "bleLife", "old ble handler address is same to macAddress")
248	                return
249	            }
250	            Log.i(tag: "bleLife", "address is not same,remove origin")
251	            guard let bleHandler = BLEHandlerFactory.createBleKeyHandler(macAddress: address, cccVid: cccVid, bleCategory: category, delegate: self, presenter: presenter, isResuce: isResuce) else {
252	                Log.i(tag: "bleLife", "create ble handler failed, return")
253	                return
254	            }
255	            return self.createNewBleHandler(bleHandler: bleHandler, bleCategory: category, presenter: presenter)
256	        } else {
257	            if BLEHandlerFactory.carKeyCCCVidIsChanged(bleHandler: oldHandler, cccVid: cccVid) == false {
258	                Log.i(tag: "bleLife", "old ble handler cccVid is same to cccVid")
259	                return
260	            } else {
261	                Log.i(tag: "bleLife", "old ble handler cccVid is not same to cccVid")
262	                self.removeOriginBleHandler()
263	                guard let bleHandler = BLEHandlerFactory.createBleKeyHandler(macAddress: address, cccVid: cccVid, bleCategory: category, delegate: self, presenter: presenter, isResuce: isResuce) else {
264	                    Log.i(tag: "bleLife", "create ble handler failed, return")
265	                    return
266	                }
267	                return self.createNewBleHandler(bleHandler: bleHandler, bleCategory: category, presenter: presenter)
268	            }
269	            return
270	        }
271	    }
