360	    public override func send(data: Any!, success: @escaping VehicleSuccessResponseCallback, failed: @escaping VehicleFailedCallback<VehicleError>) {
361	        
362	        guard let data = data as? BleSendData else {
363	            failed(VehicleError(code: .ParamError, desc: "参数错误", channel: .BLE))
364	            return
365	        }
366	        
367	        guard connectState == .Available else {
368	            failed(VehicleError(code: .BLENotConnected, desc: "蓝牙未连接", channel: .BLE))
369	            return
370	        }
371	        
372	        DispatchQueue.main.async {
373	            self.bleSwitcheCheck.isSendingBLECommand = true
374	            self.sendBleData(data)
375	                .sink {[weak self] complete in
376	                    self?.bleSwitcheCheck.isSendingBLECommand = false
377	                    switch complete {
378	                    case .failure(let error):
379	                        failed(error)
380	                    case .finished: break
381	                    }
382	                } receiveValue: { data in
383	                    success(nil)
384	                }
385	                .store(in: &self.cancellables)
386	        }
387	        
388	    }
