402	    func bleErrorToVehicleError(error: BleDeviceError) -> VehicleError {
403	        switch error {
404	        case .unconnectable:
405	            return VehicleError(code: .UnknownError, desc: error.description, channel: .BLE)
406	        case .writeTimeOut:
407	            return VehicleError(code: .Timeout, desc: error.description, channel: .BLE)
408	        case .writeError:
409	            return VehicleError(code: .BLEWriteError, desc:  error.description, channel: .BLE)
410	        case .bleNotConnect:
411	            return VehicleError(code: .BLENotConnected, desc: error.description, channel: .BLE)
412	        case .deviceDealloc:
413	            return VehicleError(code: .UnknownError, desc: error.description, channel: .BLE)
414	        case .characteristicNotFound:
415	            return VehicleError(code: .EnvironmentError, desc:error.description, channel: .BLE)
416	        case .unowned:
417	            return VehicleError(code: .UnknownError, desc: error.description, channel: .BLE)
418	            
419	        default:
420	            return VehicleError(code: .UnknownError, desc: error.description ?? "未知错误", channel: .BLE)
421	        }
422	    }
