88	    /// 处理连接状态变化（由 $connectState 触发）
89	    private func handleConnectStateChanged(state: BLEConnectionState) {
90	        Log.i(XiaopengBLEConnectionConnectTAG, "连接状态变化", "state: \(state)")
91	        // 连接成功后的业务逻辑
92	        if state == .Available {
93	            self.reconnectCount = 0
94	            self.notifyCarState()
95	            self.notifyNeededData()
96	            self.trackingConnect(error: nil)
97	        } else if state == .NotConnected {
98	            if let selfKeyHandler = self.bleHandler as? BLESelfKeyHandler {
99	                self.connectIfneed()
100	            }
101	        }
102	    }
