114	    /// 原子性连接操作（仅在需要时执行）
115	    private func performConnectIfNeeded() {
116	        guard bleSwitcheCheck.isNeedsConnect else {
117	            Log.i(XiaopengBLEConnectionConnectTAG, "连接检查", "不需要连接")
118	            return
119	        }
120	        
121	        guard let handler = self.bleHandler else {
122	            Log.i(XiaopengBLEConnectionConnectTAG, "连接检查", "handler 为 nil")
123	            return
124	        }
125	        
126	        let connectState = self.connectState
127	        // 如果状态不一致，先同步状态
128	        if connectState != handler.state {
129	            DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {
130	                if connectState == handler.state {
131	                    self.connectIfneed()
132	                }
133	            }
134	            Log.i(XiaopengBLEConnectionConnectTAG, "❌ 状态不一致！connectState 应为 \(handler.state)，正在同步...")
135	            return
136	        }
137	        
138	        guard connectState == .NotConnected else {
139	            Log.i(XiaopengBLEConnectionConnectTAG, "连接检查", "当前状态不是未连接: \(connectState)，无需发起连接")
140	            return
141	        }
142	        
143	        Log.i(XiaopengBLEConnectionConnectTAG, "✅ 蓝牙需要连接，发起连接")
144	        handler.connect()
145	    }
