148	    private func handleRetryConnect() {
149	        guard BleCentral.shared.bleState == .poweredOn else {
150	            return
151	        }
152	        
153	        guard let handler = self.bleHandler else {
154	            return
155	        }
156	        
157	        let connectState = self.connectState
158	        // 如果状态不一致，先同步状态
159	        if connectState != handler.state {
160	            DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {
161	                if connectState == handler.state {
162	                    self.connectIfneed()
163	                }
164	            }
165	            Log.i(XiaopengBLEConnectionConnectTAG, "❌ 状态不一致！connectState 应为 \(handler.state)，正在同步...")
166	            return
167	        }
168	        
169	        guard connectState != .Available else {
170	            return
171	        }
172	        
173	        if self.reconnectCount <= handler.getReconnectCount() {
174	            // 检查是否处于鉴权中
175	            if let selfKeyHandler = handler as? BLESelfKeyHandler {
176	                if selfKeyHandler.device.state == .Available {
177	                    Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙连接检查", "处于鉴权中, 不断开")
178	                    return
179	                }
180	                if connectState == .NotConnected {
181	                    Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙连接检查", "检查到蓝牙未连接，检测是否需要连接")
182	                    self.connectIfneed()
183	                    return
184	                }
185	                guard self.checkDisconnectIfNeed() else {
186	                    return
187	                }
188	                self.reconnectCount += 1
189	                if self.reconnectCount >= 5 && self.tboxRunException {
190	                    NotificationCenter.default.post(name: VehicleNotification.rescueKeyConnectFailedMoreTimeNotification,
191	                                                    object: nil,
192	                                                    userInfo: nil)
193	                    return
194	                }
195	                Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙重连", "断开重连：\(self.reconnectCount)")
196	                self.bleSwitcheCheck.disconnect(waitTime: 0.2)
197	            } else {
198	                self.reconnectCount += 1
199	                if connectState == .NotConnected {
200	                    Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙连接检查", "检查到蓝牙未连接，检测是否需要连接")
201	                    self.connectIfneed()
202	                    return
203	                }
204	            }
205	        }
206	    }
