218	    private func checkDisconnectIfNeed() -> Bool {
219	        // 间距大于8s app 休眠被唤醒 该次 不断开。
220	        let currentTime = Date().timeIntervalSince1970
221	        if currentTime - bleDisconnectInterval < 8 {
222	            bleDisconnectInterval = currentTime
223	            return true
224	        }
225	        bleDisconnectInterval = currentTime
226	        return false
227	    }
