330	    private func notifyNeededData() {
331	        self.keySettingData = self.getVaildKeySettingData()
332	        guard let presenter = self.presenter else {
333	            return
334	        }
335	        guard self.connectState == .Available else {
336	            return
337	        }
338	        guard let builder = bleSendDataBuilder as? BleSendDataBuilderV3 else { return }
339	        
340	        // 构建所有需要发送的数据
341	        let customeData = builder.pollingCustomeDataV2(
342	            isWelcome: self.keySettingData.unlockIsWelcome,
343	            pollingSwitch: self.keySettingData.pollingMode.rawValue,
344	            unlockDistance: self.keySettingData.unlockDistance,
345	            lockDistance: self.keySettingData.lockDistance,
346	            isUseSelfCalibration: self.keySettingData.isUseSelfCalibration(),
347	            selfClibrationData: self.keySettingData.fetchSelfCalibrationDataKey()
348	        )
349	        
350	        let enableData = builder.pollingEnableConfigDataV2(
351	            pollingEnableSwitch: self.keySettingData.pollingEnableSwitch
352	        )
353	        
354	        let parkingLimitData = builder.parkingLimitDistanceDataV2(
355	            isLimit: UInt8(presenter.vehiclePreference.parkLimitSixMeter ? 1 : 0)
356	        )
357	        
358	        let deviceModelData = builder.deviceModelDataV2(deviceModel: BleAuthData.getDeviceModel())
359	        
360	        // 收集所有非空数据
361	        let allData: [Data?] = [
362	            customeData,
363	            enableData,
364	            parkingLimitData,
365	            deviceModelData
366	        ]
367	        
368	        Log.i(XiaopengBLEConnectionConnectTAG, "准备发送组合数据", """
369	            customeData: \(customeData?.count ?? 0) bytes
370	            enableData: \(enableData?.count ?? 0) bytes
371	            parkingLimitData: \(parkingLimitData?.count ?? 0) bytes
372	            deviceModelData: \(deviceModelData?.count ?? 0) bytes
373	            """)
374	        
375	        let combinedDataArray = self.optimizeCombination(allData, maxBytes: 196)
376	        
377	        // 如果组合后的数组为空，直接返回
378	        guard !combinedDataArray.isEmpty else {
379	            Log.w(XiaopengBLEConnectionConnectTAG, "no vaild data to notify")
380	            return
381	        }
382	        
383	        guard let handleDataArray = builder.combinedNotityData(combinedData: combinedDataArray) else { return }
384	        
385	        // 发送组合后的数据
386	        builder.buildNotifyCombinedData(combinedData: handleDataArray)
387	            .flatMap({[weak self] data in
388	                guard let self else {
389	                    return Fail<AnyObject?, VehicleError>(error: VehicleError(code: .EnvironmentError, desc: "未知错误", channel: .BLE)).eraseToAnyPublisher()
390	                }
391	                return self.sendBleData(data)
392	            })
393	            .sink(
394	                receiveCompletion: { complete in
395	                    switch complete {
396	                    case .failure(let error):
397	                        Log.e("buildNotifyCombinedData 失败")
398	                    case .finished: break
399	                    }
400	                },
401	                receiveValue: { data in
402	                    Log.i("buildNotifyCombinedData 成功")
403	                }
404	            ).store(in: &cancellables)
