407	    private func optimizeCombination(_ dataArray: [Data?], maxBytes: Int = 200) -> [Data] {
408	        let validDataArray = dataArray.compactMap { $0 }
409	        
410	        guard !validDataArray.isEmpty else {
411	            return []
412	        }
413	        
414	        var result: [Data] = []
415	        var currentGroup = Data()
416	        
417	        // 按数据大小排序（降序），优先放大的数据
418	        let sortedData = validDataArray.sorted { $0.count > $1.count }
419	        
420	        Log.i(XiaopengBLEConnectionConnectTAG, "[数据组合] 原始数据数量: \(validDataArray.count)")
421	        
422	        for data in sortedData {
423	            // 如果单个数据就超过限制，单独发送
424	            if data.count > maxBytes {
425	                Log.w(XiaopengBLEConnectionConnectTAG, "[数据组合] 单个数据大小 \(data.count) bytes 超过限制 \(maxBytes) bytes，将单独发送")
426	                result.append(data)
427	                continue
428	            }
429	            
430	            // 尝试添加到当前组
431	            if currentGroup.count + data.count <= maxBytes {
432	                currentGroup.append(data)
433	            } else {
434	                // 当前组已满，开启新组
435	                if !currentGroup.isEmpty {
436	                    result.append(currentGroup)
437	                }
438	                currentGroup = data
439	            }
440	        }
441	        
442	        // 添加最后一组
443	        if !currentGroup.isEmpty {
444	            result.append(currentGroup)
445	        }
446	        
447	        Log.i(XiaopengBLEConnectionConnectTAG, "[数据组合] 组合后数量: \(result.count)")
448	        
449	        return result
450	    }
451	}
