550	    enum DetectStopReason: Int {
551	        case timeout = 0     // 超时
552	        case connected      // 蓝牙已连接
553	        case categoryChange // 蓝牙钥匙类型变化
554	        case unlocked       // 门锁状态变化
555	        case manual         // 手动停止
556	    }
557	    
558	    func detectIsNearCar(beaconState: IBeaconState, _ timeout: TimeInterval = 60) {
559	        if beaconState == .enter {
560	            guard let presenter = self.presenter else {
561	                Log.i(tag:"detect", "presenter is nil")
562	                return
563	            }
564	            if presenter.vehiclePreference.function.CCC_DK_THIRD == false {
565	                Log.i(tag:"detect", "CCC_DK_THIRD is false")
566	                return
567	            }
568	            guard let macAddress = presenter.digitalKeyManager?.validBlePrivateKey()?.bleInfo?.macAddress else {
569	                Log.i(tag:"detect", "macAddress is nil")
570	                return
571	            }
572	            guard presenter.digitalKeyManager?.vaildBleKeyCategory() == .PHONE_UWB_KEY else {
573	                Log.i(tag:"detect", "current key is not uwb key")
574	                return
575	            }
576	            guard presenter.vehicleState.door?.driver_door_lock_st != .unlocked else {
577	                Log.i(tag:"detect", "door lock is unlocked")
578	                return
579	            }
580	            guard self.connectState != .Available else {
581	                Log.i(tag:"detect", "car key is connected, no need to detect")
582	                return
583	            }
584	            guard self.isDetecting == false else {
585	                Log.i(tag:"detect", "detect is working")
586	                return
587	            }
588	            self.isDetecting = true
589	            Log.i(tag:"detect", "begin detect, timeout: \(timeout)秒")
590	            self.detectCancellables?.removeAll()
591	            self.discoveryArray?.removeAll()
592	            self.detectCancellables = Set<AnyCancellable>()
593	            self.discoveryArray = []
594	            self.detectBeginTime = CACurrentMediaTime()
595	            let ssidPrefix = presenter.vehiclePreference.abilityConfig.bleSsidPrefix
596	            let detectDevice = BleDevice(ssidPrefix: ssidPrefix, macAddress: macAddress, useScanUUIDs: true, useRssiNotify: false)
597	            self.detectDevice = detectDevice
598	            
599	            // 超时触发器
600	            let timeoutTrigger = Timer.publish(every: timeout, on: .main, in: .common)
601	                .autoconnect()
602	                .first()
603	                .map { _ in DetectStopReason.timeout }
604	            
605	            // 连接成功触发器
606	            let connectionTrigger = self.$connectState
607	                .filter { $0 == .Available }
608	                .first()
609	                .map { _ in DetectStopReason.connected }
610	            
611	            let categoryChangeTrigger = self.$bleCategory
612	                .filter { $0 != .PHONE_UWB_KEY }
613	                .first()
614	                .map { _ in DetectStopReason.categoryChange }
615	            
616	            let unlockTrigger = self.recieveBleVehicleStatePublisher
617	                .filter { state in
618	                    return state.door?.driver_door_lock_st == .unlocked
619	                }
620	                .first()
621	                .map { _ in DetectStopReason.unlocked }
622	                
623	            // 合并触发器：任一触发即停止
624	            let stopTrigger = Publishers.Merge4(timeoutTrigger, connectionTrigger, categoryChangeTrigger, unlockTrigger)
625	                .first()
626	                .handleEvents(receiveOutput: { [weak self] reason in
627	                    guard let self = self else { return }
628	                    switch reason {
629	                    case .timeout:
630	                        Log.i(tag:"detect", "超时触发器触发（\(timeout)秒）")
631	                    case .connected:
632	                        Log.i(tag:"detect", "蓝牙已连接，停止扫描")
633	                    case .categoryChange:
634	                        Log.i(tag:"detect", "蓝牙钥匙类型变化，停止扫描")
635	                    case .unlocked:
636	                        Log.i(tag:"detect", "门锁状态变化，停止扫描")
637	                    case .manual:
638	                        Log.i(tag:"detect", "手动停止扫描")
639	                    }
640	                    self.stopDetecting(reason: reason)
641	                })
642	            
643	            // 扫描流：当 stopTrigger 触发时自动停止
644	            let detectMonitor = detectDevice.startDetect()
645	                .prefix(untilOutputFrom: stopTrigger)
646	                .sink(receiveValue: { [weak self] discovery in
647	                    guard let self = self else { return }
648	                    Log.i(tag:"detect", "扫描到设备，rssi:\(discovery.rssi ?? 0)db, name:\(discovery.peripheral.name ?? "nil")")
649	                    self.discoveryArray?.append(discovery)
650	                })
651	            
652	            self.detectCancellables?.insert(detectMonitor)
653	        }
654	    }
655	    
656	    func stopDetecting(reason: DetectStopReason) {
657	        // 停止扫描并清理资源
658	        self.detectDevice?.stopScan()
659	        if self.isDetecting {
660	            self.isDetecting = false
661	            self.detectCancellables?.removeAll()
662	            self.handleSuccessDeletctFlow(reason: reason)
663	            self.detectBeginTime = 0
664	        }
665	    }
666	    
667	    func handleSuccessDeletctFlow(reason: DetectStopReason) {
668	        guard let discoveryArray = self.discoveryArray, discoveryArray.count > 0 else {
669	            Log.i(tag:"detect", "没有扫描到设备")
670	            return
671	        }
672	        var leastCount: Int = 0 // -70db
673	        var lessCount: Int = 0 //
674	        var middleCount: Int = 0
675	        var greatCount: Int = 0
676	        for discovery in discoveryArray {
677	            guard let rssi = discovery.rssi, rssi < 0 else {
678	                continue
679	            }
680	            if rssi >= -60 && rssi <= 0 {
681	                greatCount += 1
682	            } else if rssi < -60 && rssi >= -65 {
683	                middleCount += 1
684	            } else if rssi < -65 && rssi >= -70 {
685	                lessCount += 1
686	            } else {
687	                leastCount += 1
688	            }
689	        }
690	        let currentTime = CACurrentMediaTime()
691	        let duration = currentTime - (self.detectBeginTime ?? currentTime)
692	        Log.i(tag:"detect", "扫描结果 近距离数量:\(greatCount) 中距离数量:\(middleCount) 远距离数量:\(lessCount) 极远距离数量:\(leastCount) 扫描时长:\(String(format: "%.2f", duration))秒, carKey连接状态：\(reason == .connected ? true : false), report_reason: \(reason.rawValue)")
693	        guard lessCount > 0 || leastCount > 0 else {
694	            Log.i(tag:"detect", "no weak rssi, return")
695	            return
696	        }
697	        Statistics.trackingCarKeyExceptionScanResult(isInBackground: AppRunState.shared.isInBackground, isConnect: reason == .connected ? true : false, rssi_times_1: leastCount, rssi_times_2: greatCount, rssi_times_3: middleCount, rssi_times_4: lessCount, scan_time: Int(duration), lock_status: self.presenter?.vehicleState.door?.driver_door_lock_st == .unlocked ? 0 : 1, report_reason: reason.rawValue)
698	    }
699	}
