233	            var vehicleState: VehicleState?
234	            
235	            if let msg_content = data?.data as? [String : Any] {
236	                if let state = self?.parseContentMsg(msg_content: msg_content) {
237	                    state.vin = self?.vin
238	                    vehicleState = state
239	                }
240	            }
241	            success?(VehicleResponse(channel: .TCP, data: vehicleState))
242	        } failed: {[weak self] error in
243	            Log.e(tag: Self.kTag, "请求车态 publish error: \(error)")
244	            failed?(error)
245	        }
246	    }
