260	            Log.i(tag: Self.kTag, "收到车态数据 车辆处于维修模式中，强制车态数据维修模式状态为维修中")
261	            vehicleState.ext?.entryTime = Date().timeIntervalSince1970 * 1000
262	        }
263	
264	
265	        self.vehicleStateChange(with: vehicleState);
