364	    func parseContentMsg(msg_content: [String : Any]) -> VehicleState? {
365	        
366	       if let digitState = parseContentDigitMsg(msg_content: msg_content) {
367	           digitState.timestamp = Date()
368	           digitState.vin = vin
369	           digitState.parseOtaString()
370	           digitVehicleStateChange(with: digitState)
371	       }
372	
373	        var state: VehicleState? = nil
374	        if let data = msg_content["instant"] {
375	            state = parseStateMsg(msg_state: data)
376	        }
377	        if let data = msg_content["interval"] {
378	            let interval_state = parseStateMsg(msg_state: data)
379	            if (state == nil) {
380	                state = interval_state;
381	            } else if (interval_state != nil) {
382	                state = state?.mergeVehicleState(from: interval_state!)
383	            }
384	        }
385	
386	        return state
387	    }
