416	    func parseContentAction(content: [String : Any]) -> ActionType? {
417	        var action: ActionType? = nil
418	        if let msgType = content["msgType"] as? String? {
419	            if (msgType == "CMD") {
420	                if let msgContent : [String : Any] = content["msgContent"] as? [String : Any] {
421	                    if msgContent["action"] as? String? == "REPAIR_MODE_COMPLETED" {
422	                        if let ext : [String : Any] = msgContent["ext"] as? [String : Any], ext["vin"] as? String? == self.vin {
423	                            action = .repairModeComplete
424	                        }
425	                    }
426	                }
427	            }
428	        }
429	        
430	        return action
431	    }
