18	@objc(XPDeviceMonitor)
19	public class DeviceMonitor: NSObject {
20	
21	    /// 获取当前任务使用的物理内存（RAM），单位 MB
22	    /// - Returns: 使用的内存大小（MB），如果获取失败返回 -1
23	    @objc public class func currentUsedMemory() -> Float {
24	        var vmInfo = task_vm_info_data_t()
25	        var count = mach_msg_type_number_t(MemoryLayout<task_vm_info_data_t>.size) / 4
26	        
27	        let kernReturn: kern_return_t = withUnsafeMutablePointer(to: &vmInfo) {
28	            $0.withMemoryRebound(to: integer_t.self, capacity: 1) {
29	                task_info(mach_task_self_, task_flavor_t(TASK_VM_INFO), $0, &count)
30	            }
31	        }
32	        
33	        if kernReturn == KERN_SUCCESS {
34	            let memoryUsageInByte = Int64(vmInfo.phys_footprint)
35	            return Float(memoryUsageInByte) / (1024 * 1024) // 转换为 MB
36	        } else {
37	            return -1
38	        }
39	    }
40	    
41	    /// 获取设备的可用内存，单位 MB
42	    /// - Returns: 可用内存大小（MB），如果获取失败返回 NSNotFound
43	    @objc public class func availableMemory() -> Float {
44	        var vmStats = vm_statistics64()
45	        var hostSize = mach_msg_type_number_t(MemoryLayout<vm_statistics64_data_t>.size / MemoryLayout<integer_t>.size)
46	        
47	        let kernReturn = withUnsafeMutablePointer(to: &vmStats) {
48	            $0.withMemoryRebound(to: integer_t.self, capacity: Int(hostSize)) {
49	                host_statistics64(mach_host_self(), HOST_VM_INFO64, $0, &hostSize)
50	            }
51	        }
52	        
53	        guard kernReturn == KERN_SUCCESS else {
54	            return Float(NSNotFound)
55	        }
56	        
57	        // 获取页面大小并计算可用内存
58	        let pageSize = Int(vm_kernel_page_size)
59	        let freeMemory = Int64(vmStats.free_count) * Int64(pageSize)
60	        return Float(freeMemory) / (1024 * 1024) // 转换为 MB
61	    }
62	    
63	    /// 获取当前任务的 CPU 使用率（所有线程的总和）
64	    /// - Returns: CPU 使用率百分比（0% ~ 100%），如果获取失败返回 -1
65	    @objc public class func cpuUsage() -> Float {
66	        var threadList: thread_act_array_t?
67	        var threadCount: mach_msg_type_number_t = 0
68	        
69	        // 获取当前任务的线程列表
70	        let kernReturn = task_threads(mach_task_self_, &threadList, &threadCount)
71	        guard kernReturn == KERN_SUCCESS, let threadList = threadList else {
72	            return -1
73	        }
74	        
75	        var totalCpuUsage: Float = 0
76	        
77	        // 遍历所有线程，累加 CPU 使用率
78	        for i in 0..<Int(threadCount) {
79	            var threadInfo = thread_basic_info()
80	            var threadInfoCount = mach_msg_type_number_t(THREAD_INFO_MAX)
81	            let threadInfoResult: kern_return_t = withUnsafeMutablePointer(to: &threadInfo) {
82	                $0.withMemoryRebound(to: integer_t.self, capacity: Int(threadInfoCount)) {
83	                    thread_info(threadList[i], thread_flavor_t(THREAD_BASIC_INFO), $0, &threadInfoCount)
84	                }
85	            }
86	            
87	            guard threadInfoResult == KERN_SUCCESS else {
88	                continue // 跳过无法获取信息的线程
89	            }
90	            
91	            // 累加非空闲线程的 CPU 使用率
92	            let flags = threadInfo.flags
93	            if flags & TH_FLAGS_IDLE == 0 { // 线程非空闲
94	                totalCpuUsage += Float(threadInfo.cpu_usage) / Float(TH_USAGE_SCALE)
95	            }
96	        }
97	        
98	        // 防止内存泄漏，释放线程列表
99	        let vmDeallocResult = vm_deallocate(mach_task_self_, vm_address_t(bitPattern: threadList), vm_size_t(threadCount) * vm_size_t(MemoryLayout<thread_t>.size))
100	        if vmDeallocResult != KERN_SUCCESS {
101	            print("Warning: Failed to deallocate thread list memory.")
102	        }
103	        
104	        // 确保返回值在合理范围内
105	        if totalCpuUsage < 0 {
106	            return 0.0
107	        } else if totalCpuUsage > 100.0 {
108	            return 100.0
109	        } else {
110	            return totalCpuUsage * 100.0 // 转换为百分比
111	        }
112	    }
113	    
114	    /// 获取当前设备电池电量
115	    /// - Returns: 电池电量百分比（0.0 ~ 1.0）
116	    @objc public class func batteryLevel() -> Float {
117	        // 确保电池监控已启用
118	        UIDevice.current.isBatteryMonitoringEnabled = true
119	        let batteryLevel = UIDevice.current.batteryLevel
120	        return Float(batteryLevel) // 返回 0.0 到 1.0 之间的值
121	    }
