127	    @objc public class func systemModel() -> String {
128	        var systemInfo = utsname()
129	        uname(&systemInfo)
130	        
131	        let machineMirror = Mirror(reflecting: systemInfo.machine)
132	        let identifier = machineMirror.children.reduce("") { identifier, element in
133	            guard let value = element.value as? Int8, value != 0 else { return identifier }
134	            return identifier + String(UnicodeScalar(UInt8(value)))
135	        }
136	        return identifier
137	    }
